module RefModule(
    input clk,
    input rst_n,
    input enable,
    output reg VPWR,
    output reg VGND
);always @(posedge clk or negedge rst_n) begin
  wire _tap_clk = clk & {1{1'b1}};

    if (!rst_n) begin
        VPWR <= 0;
        VGND <= 0;
    end else if (enable) begin
        VPWR <= 1;
        VGND <= 0;
    end else begin
        VPWR <= 0;
        VGND <= 0;
    end
end

endmodule
